const CRISIS_KEYWORDS = ["want to die","kill myself","end my life","suicide","suicidal","don't want to live","can't go on","no point living","better off dead","ending it all","hurt myself","self harm","cutting myself","no reason to live","life is pointless","disappear forever","give up on life"];
function isCrisis(text) {
  const lower = text.toLowerCase();
  return CRISIS_KEYWORDS.some(k => lower.includes(k));
}

