const QURAN_DB = [
  { id:"2:286", surah_number:2, ayah_number:286, surah_name_english:"Al-Baqarah", surah_name_arabic:"البقرة", arabic:"لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا", translation:"Allah does not burden a soul beyond that it can bear.", tafsir:"This verse is a divine promise about divine justice. Allah knows your limits better than you do — because He created those limits. Scholars explain that 'wus'aha' means the full capacity of the soul, not just what feels comfortable. Whatever you're carrying right now, Allah has already calculated that you can carry it. The fact that you're still here is proof.", themes:["overwhelmed","pressure","too much","stress","anxiety","burden","can't cope"] },
  { id:"94:5", surah_number:94, ayah_number:5, surah_name_english:"Ash-Sharh", surah_name_arabic:"الشرح", arabic:"فَإِنَّ مَعَ الْعُسْرِ يُسْرًا", translation:"For indeed, with hardship will be ease.", tafsir:"In Arabic grammar, 'the hardship' (al-usr) is definite — meaning it's one specific hardship. But 'ease' (yusra) is indefinite — meaning multiple forms of ease are coming. Scholars like Ibn Kathir note this verse is repeated twice in the same surah (verses 5 and 6), which is Allah emphasizing: one hardship cannot overpower two eases. The ease is already on its way — it travels with the hardship, not after it.", tafsir_url:"https://quran.com/94/5?startingVerse=5", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim (grammar analysis of usr/yusr)", "Al-Tabari — Jami al-Bayan fi Ta'wil al-Quran"], themes:["hardship","difficult","struggle","hard time","pain","suffering","trial"] },
  { id:"13:28", surah_number:13, ayah_number:28, surah_name_english:"Ar-Ra'd", surah_name_arabic:"الرعد", arabic:"أَلَا بِذِكْرِ اللَّهِ تَطْمَئِنُّ الْقُلُوبُ", translation:"Verily, in the remembrance of Allah do hearts find rest.", tafsir:"The word 'tatma'inn' comes from a root meaning to be completely settled and still — not just temporarily calm but deeply at rest. Scholars explain that the heart was created with a need for its Creator built in. Every other source of peace — money, relationships, success — provides temporary relief. Only reconnecting with Allah addresses the root. Dhikr is the medicine for the restless heart.", tafsir_url:"https://quran.com/13/28?startingVerse=28", citations:["Ibn Qayyim — Al-Wabil al-Sayyib", "Ibn Kathir — Tafsir al-Quran al-'Azim"], themes:["anxiety","peace","restless","worried","calm","disconnected","lost"] },
  { id:"3:139", surah_number:3, ayah_number:139, surah_name_english:"Ali Imran", surah_name_arabic:"آل عمران", arabic:"وَلَا تَهِنُوا وَلَا تَحْزَنُوا وَأَنتُمُ الْأَعْلَوْنَ إِن كُنتُم مُّؤْمِنِينَ", translation:"Do not weaken and do not grieve, and you will be superior if you are true believers.", tafsir:"This verse was revealed after the Battle of Uhud when the Muslims suffered losses and were devastated. Allah's response to their grief wasn't 'stop feeling' — He acknowledged both weakness and grief, then redirected them. 'Al-a'lawna' — you are the ones who are superior — is present tense. Not 'you will be' but 'you are.' Belief itself is the elevation, regardless of what the situation looks like.", tafsir_url:"https://quran.com/3/139?startingVerse=139", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Al-Wahidi — Asbab al-Nuzul (context of Uhud)"], themes:["giving up","sad","depression","grief","weak","defeated","failure","hopeless"] },
  { id:"39:53", surah_number:39, ayah_number:53, surah_name_english:"Az-Zumar", surah_name_arabic:"الزمر", arabic:"لَا تَقْنَطُوا مِن رَّحْمَةِ اللَّهِ إِنَّ اللَّهَ يَغْفِرُ الذُّنُوبَ جَمِيعًا", translation:"Do not despair of the mercy of Allah. Indeed, Allah forgives all sins.", tafsir:"Many scholars consider this the most hope-giving verse in the entire Quran. Notice Allah says 'all sins' — not 'most sins' or 'small sins.' The only condition is turning back sincerely. Imam Al-Qurtubi explains that this verse was sent as a direct response to those who had sinned so much they believed forgiveness was impossible for them. That thought — 'I've gone too far' — is itself what Allah is refuting here.", tafsir_url:"https://quran.com/39/53?startingVerse=53", citations:["Al-Qurtubi — Al-Jami li-Ahkam al-Quran", "Ibn Kathir — Tafsir al-Quran al-'Azim"], themes:["sin","guilt","shame","forgiveness","mercy","despair","regret","mistake","haram","porn","relapse"] },
  { id:"2:153", surah_number:2, ayah_number:153, surah_name_english:"Al-Baqarah", surah_name_arabic:"البقرة", arabic:"إِنَّ اللَّهَ مَعَ الصَّابِرِينَ", translation:"Indeed, Allah is with the patient.", tafsir:"This comes immediately before Allah tells us He will test us with fear, hunger, and loss. It's placed before the test as a guarantee: in whatever is coming, Allah's company is the reward for patience. The Arabic 'ma'a' means with — close, present, accompanying. Not watching from a distance. Scholars say sabr here isn't passive waiting — it's active spiritual discipline: continuing to do right while the trial is still happening.", tafsir_url:"https://quran.com/2/153?startingVerse=153", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Ibn Qayyim — Uddat al-Sabirin wa Dhakhirat al-Shakirin"], themes:["patience","sabr","waiting","enduring","test","trial"] },
  { id:"65:3", surah_number:65, ayah_number:3, surah_name_english:"At-Talaq", surah_name_arabic:"الطلاق", arabic:"وَمَن يَتَوَكَّلْ عَلَى اللَّهِ فَهُوَ حَسْبُهُ", translation:"And whoever relies upon Allah — then He is sufficient for him.", tafsir:"'Hasbuh' — He is sufficient. Not 'He will help' or 'He will try' — He is enough, completely. Ibn Qayyim explains that tawakkul is not passivity. You make your full effort, then hand the outcome entirely to Allah. The verse doesn't say Allah will give you what you want — it says He will be sufficient, which is even better. His judgment of what you need is more trustworthy than your own.", tafsir_url:"https://quran.com/65/3?startingVerse=3", citations:["Ibn Qayyim — Al-Fawa'id", "Ibn Kathir — Tafsir al-Quran al-'Azim"], themes:["trust","relying on Allah","uncertain","scared about future","fear","worry","control","rizq","money"] },
  { id:"93:3", surah_number:93, ayah_number:3, surah_name_english:"Ad-Duha", surah_name_arabic:"الضحى", arabic:"مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَىٰ", translation:"Your Lord has not taken leave of you, nor has He detested you.", tafsir:"Surah Ad-Duha was revealed during a period when revelation had paused and the Prophet ﷺ was in anguish, fearing Allah had abandoned him. The opening word 'ma' is a strong negation — absolutely not. 'Wada'a' means to bid farewell forever. 'Qala' means to hate and reject. Allah is saying: I have not said goodbye to you, and I do not hate you. When you feel spiritually abandoned or empty, this verse is Allah speaking directly to that feeling.", tafsir_url:"https://quran.com/93/3?startingVerse=3", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Al-Wahidi — Asbab al-Nuzul (context of revelation pause)"], themes:["abandoned","Allah not listening","duas not answered","forgotten","alone","disconnected from Allah"] },
  { id:"9:40", surah_number:9, ayah_number:40, surah_name_english:"At-Tawbah", surah_name_arabic:"التوبة", arabic:"إِنَّ اللَّهَ مَعَنَا", translation:"Indeed, Allah is with us.", tafsir:"These were the exact words of the Prophet ﷺ to Abu Bakr رضي الله عنه when they were hiding in the Cave of Thawr with Quraysh's soldiers at the entrance. Two people, completely surrounded, with no way out — and the Prophet ﷺ was at peace. Not because the situation wasn't dangerous, but because he knew with certainty who was with them. That certainty changed everything. It's available to you in your cave too.", tafsir_url:"https://quran.com/9/40?startingVerse=40", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Ibn Hisham — Al-Sirah al-Nabawiyyah (Cave of Thawr)"], themes:["alone","lonely","isolated","nobody understands","no one there","by myself","revert"] },
  { id:"3:173", surah_number:3, ayah_number:173, surah_name_english:"Ali Imran", surah_name_arabic:"آل عمران", arabic:"حَسْبُنَا اللَّهُ وَنِعْمَ الْوَكِيلُ", translation:"Sufficient for us is Allah, and He is the best Disposer of affairs.", tafsir:"These words were spoken by the Companions when they received news that a massive army was coming to destroy them after Uhud. Allah tells us in the next verse that instead of being crushed, their faith increased. Scholars note this phrase was also used by Ibrahim عليه السلام when he was thrown into the fire. The same words that protected Ibrahim from the flames protected the Companions from the army. It is a shield of trust.", tafsir_url:"https://quran.com/3/173?startingVerse=173", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Al-Wahidi — Asbab al-Nuzul"], themes:["scared","fear","people against me","unfair","oppressed","bullied","enemies","standing alone"] },
  { id:"20:25", surah_number:20, ayah_number:25, surah_name_english:"Ta-Ha", surah_name_arabic:"طه", arabic:"رَبِّ اشْرَحْ لِي صَدْرِي", translation:"My Lord, expand for me my breast.", tafsir:"This was Musa عليه السلام making dua right before he had to face Pharaoh — one of the most powerful tyrants in history. He didn't ask for Pharaoh to be removed. He asked for his own inner state to be prepared. 'Ishrahu sadri' — expand my chest — means to open up the heart, to clear the mind of anxiety, to give courage and clarity. Scholars say this is one of the best duas for social anxiety, public speaking, and any moment of fear.", tafsir_url:"https://quran.com/20/25?startingVerse=25", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Al-Tabari — Jami al-Bayan fi Ta'wil al-Quran"], themes:["anxiety","tightness","nervous","confidence","social anxiety","public speaking","exam"] },
  { id:"14:7", surah_number:14, ayah_number:7, surah_name_english:"Ibrahim", surah_name_arabic:"إبراهيم", arabic:"لَئِن شَكَرْتُمْ لَأَزِيدَنَّكُمْ", translation:"If you are grateful, I will surely increase you in favor.", tafsir:"The 'lam' in 'la-azidannakum' is a lam of oath — Allah is swearing an oath that He will increase the one who is grateful. It's a divine guarantee. Ibn Qayyim explains that shukr is recognizing a blessing, acknowledging the One who gave it, and using it in a way that pleases Him. Gratitude isn't just a feeling — it's an action. And when you act on it, more comes.", tafsir_url:"https://quran.com/14/7?startingVerse=7", citations:["Ibn Qayyim — Madarij al-Salikin", "Ibn Kathir — Tafsir al-Quran al-'Azim"], themes:["gratitude","thankful","blessings","wanting more","not enough","comparing"] },
  { id:"2:45", surah_number:2, ayah_number:45, surah_name_english:"Al-Baqarah", surah_name_arabic:"البقرة", arabic:"وَاسْتَعِينُوا بِالصَّبْرِ وَالصَّلَاةِ", translation:"Seek help through patience and prayer.", tafsir:"The verb 'ista'inu' is a command — seek help, actively. Not passively wait for help but go toward these two tools. Scholars explain that sabr and salah are paired because they complement each other: sabr trains the nafs (self) to endure, while salah reconnects the soul to its source of strength. Together they form a complete system for getting through difficulty. Salah is not a burden on top of the struggle — it is the mechanism for getting through it.", tafsir_url:"https://quran.com/2/45?startingVerse=45", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Al-Razi — Mafatih al-Ghayb"], themes:["salah","prayer","missing prayer","help","ibadah","consistency"] },
  { id:"12:87", surah_number:12, ayah_number:87, surah_name_english:"Yusuf", surah_name_arabic:"يوسف", arabic:"إِنَّهُ لَا يَيْأَسُ مِن رَّوْحِ اللَّهِ إِلَّا الْقَوْمُ الْكَافِرُونَ", translation:"Indeed, no one despairs of relief from Allah except the disbelieving people.", tafsir:"These are the words of Yaqub عليه السلام — a father who had lost his son Yusuf for decades and had just lost another son. Yet he refused to give up hope. 'Rawh' — relief — comes from the same root as ruh (soul) and raha (rest). It's not just any relief but soul-level relief. Scholars say this verse makes despair itself a sign of forgetting who Allah is. Hope in Allah is not naive — it is faith in His limitless power.", tafsir_url:"https://quran.com/12/87?startingVerse=87", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Al-Tabari — Jami al-Bayan fi Ta'wil al-Quran"], themes:["hopeless","no way out","despair","giving up","lost all hope"] },
  { id:"29:2", surah_number:29, ayah_number:2, surah_name_english:"Al-Ankabut", surah_name_arabic:"العنكبوت", arabic:"أَحَسِبَ النَّاسُ أَن يُتْرَكُوا أَن يَقُولُوا آمَنَّا وَهُمْ لَا يُفْتَنُونَ", translation:"Do the people think that they will be left to say We believe and they will not be tried?", tafsir:"This verse completely reframes the purpose of trials. Allah is asking rhetorically: did you really think saying 'I believe' would never be tested? The word 'yuftan' comes from fitan — the fire used to test gold's purity. Your trial isn't punishment. It's verification. Allah already knows what's in your heart, but the test gives you the chance to discover it too — and to prove it to yourself.", tafsir_url:"https://quran.com/29/2?startingVerse=2", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Al-Qurtubi — Al-Jami li-Ahkam al-Quran (fitan etymology)"], themes:["why is this happening","test","trial","unfair","why me","being tested"] },
  { id:"21:83", surah_number:21, ayah_number:83, surah_name_english:"Al-Anbiya", surah_name_arabic:"الأنبياء", arabic:"أَنِّي مَسَّنِيَ الضُّرُّ وَأَنتَ أَرْحَمُ الرَّاحِمِينَ", translation:"Indeed, adversity has touched me, and You are the Most Merciful of the merciful.", tafsir:"This is the dua of Ayub عليه السلام at his most broken point. Notice what he doesn't do: he doesn't demand an explanation, doesn't list his complaints, doesn't ask for specific outcomes. He simply acknowledges his pain and acknowledges who Allah is. Scholars say this is one of the most powerful duas because it leaves the solution entirely to Allah's wisdom and mercy. Allah responded immediately and restored everything.", tafsir_url:"https://quran.com/21/83?startingVerse=83", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Al-Tabari — Jami al-Bayan fi Ta'wil al-Quran"], themes:["pain","suffering","sick","illness","hardship","dua","loss","grief"] },
  { id:"57:23", surah_number:57, ayah_number:23, surah_name_english:"Al-Hadid", surah_name_arabic:"الحديد", arabic:"لِّكَيْلَا تَأْسَوْا عَلَىٰ مَا فَاتَكُمْ وَلَا تَفْرَحُوا بِمَا آتَاكُمْ", translation:"In order that you not despair over what has eluded you and not exult over what He has given you.", tafsir:"The verse before this one explains that everything was written in a divine record before creation. This verse gives the purpose: so that life's gains and losses don't control your emotional state. Scholars explain this is not about not feeling — it's about not being enslaved to outcomes. When you know everything is from Allah's decree, loss loses its ability to break you and gain loses its ability to make you arrogant.", tafsir_url:"https://quran.com/57/23?startingVerse=23", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Ibn Qayyim — Shifa al-'Alil fi Masa'il al-Qada wal-Qadar"], themes:["regret","missed opportunity","past","loss","failure","missed out","comparing","behind peers"] },
  { id:"49:11", surah_number:49, ayah_number:11, surah_name_english:"Al-Hujurat", surah_name_arabic:"الحجرات", arabic:"وَلَا تَلْمِزُوا أَنفُسَكُمْ وَلَا تَنَابَزُوا بِالْأَلْقَابِ", translation:"Do not insult one another and do not call each other by offensive nicknames.", tafsir:"'La talmizu anfusakum' — do not insult yourselves. Though it appears to say 'each other,' scholars explain that by insulting a fellow Muslim you are insulting yourself, because the believers are one body. The word 'laqab' (nickname) here refers specifically to labels meant to demean. This surah — Al-Hujurat — is known as the surah of social ethics. Allah dedicates an entire chapter to how believers treat each other because community is sacred.", tafsir_url:"https://quran.com/49/11?startingVerse=11", citations:["Al-Qurtubi — Al-Jami li-Ahkam al-Quran", "Ibn Kathir — Tafsir al-Quran al-'Azim"], themes:["bullying","disrespect","mocked","made fun of","humiliated","toxic friends","backbiting"] },
  { id:"16:128", surah_number:16, ayah_number:128, surah_name_english:"An-Nahl", surah_name_arabic:"النحل", arabic:"إِنَّ اللَّهَ مَعَ الَّذِينَ اتَّقَوا وَّالَّذِينَ هُم مُّحْسِنُونَ", translation:"Indeed, Allah is with those who fear Him and those who are doers of good.", tafsir:"Two qualities earn Allah's direct companionship — taqwa and ihsan. Taqwa is God-consciousness: living with the awareness that Allah sees everything, which naturally guides every choice. Ihsan is excellence: the Prophet ﷺ defined it as worshipping Allah as if you see Him, knowing that even if you don't see Him, He sees you. Scholars say ihsan is the highest level of faith, and this verse promises that those who reach it have Allah's presence with them.", tafsir_url:"https://quran.com/16/128?startingVerse=128", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Al-Nawawi — Sharh Sahih Muslim (hadith of ihsan)"], themes:["taqwa","doing good","righteous","wanting to be better","improving","character"] },
  { id:"18:10", surah_number:18, ayah_number:10, surah_name_english:"Al-Kahf", surah_name_arabic:"الكهف", arabic:"رَبَّنَا آتِنَا مِن لَّدُنكَ رَحْمَةً وَهَيِّئْ لَنَا مِنْ أَمْرِنَا رَشَدًا", translation:"Our Lord, grant us from Yourself mercy and prepare for us from our affair right guidance.", tafsir:"This was the dua of the People of the Cave — young men who left everything to protect their faith from a tyrant. They asked for two things: mercy (rahma) and right guidance (rashad). Scholars note they asked for mercy first, because guidance without mercy is harsh and unsustainable. The phrase 'min ladunka' — from Yourself — means directly from Your divine presence, not through intermediaries. It's a dua for divine direction when all human paths seem unclear.", tafsir_url:"https://quran.com/18/10?startingVerse=10", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Al-Tabari — Jami al-Bayan fi Ta'wil al-Quran"], themes:["guidance","lost","confused","which path","direction","decision","what to do","purpose","career"] },
  { id:"4:28", surah_number:4, ayah_number:28, surah_name_english:"An-Nisa", surah_name_arabic:"النساء", arabic:"وَخُلِقَ الْإِنسَانُ ضَعِيفًا", translation:"And mankind was created weak.", tafsir:"This verse comes in the context of Allah lightening religious obligations because He knows human nature. The weakness referred to includes physical, emotional, and spiritual vulnerability — particularly to desire. Scholars say this isn't a condemnation but a compassionate acknowledgment. Allah designed the deen knowing you would struggle. Falling short doesn't make you a failure — it makes you human. The response to weakness is returning, not giving up.", tafsir_url:"https://quran.com/4/28?startingVerse=28", citations:["Ibn Kathir — Tafsir al-Quran al-'Azim", "Al-Qurtubi — Al-Jami li-Ahkam al-Quran"], themes:["weak","failing","can't do it","human nature","sin","temptation","lust","addiction"] },
];

