const PROPHET_STORIES = [
  { id:"yusuf_betrayal", prophet:"Yusuf عليه السلام", title:"Thrown in a Well by His Own Brothers", themes:["betrayal","family","jealousy","unfair","backstabbed","trusted someone who hurt me","toxic friends","left out"], story:"Yusuf عليه السلام was his father's favorite, and his brothers hated him for it. Not strangers — his own brothers. They threw him into a dark well and sold him into slavery, then went home and lied to their father's face. He went from being loved at home to being a slave in a foreign country overnight. And yet the Quran doesn't show us Yusuf breaking down or losing faith. He held onto Allah in the dark of that well. Years later, after prison, after being forgotten, Allah elevated him to a position where those same brothers came to him begging for help. He didn't take revenge. He said 'No blame will there be upon you today.' The person who hurt you the most cannot stop what Allah has written for you.", key_lesson:"The people who betrayed you cannot stop your destiny. Hold onto Allah in the dark.", ayah_ref:"12:87" },
  { id:"musa_fear", prophet:"Musa عليه السلام", title:"Running for His Life with Nowhere to Go", themes:["scared","running away","no way out","trapped","fear","anxiety","impossible situation","enemies","alone","revert feeling alone"], story:"Musa عليه السلام accidentally killed a man and had to flee Egypt overnight with nothing. No plan, no money, no destination — just running. He ended up alone in the desert, exhausted, sitting under a tree with nothing to eat. He made one of the most honest duas in the Quran: 'My Lord, indeed I am in need of whatever good You would send down to me.' No long speech. Just raw honesty. And within hours his whole life changed. Then years later when he was leading his people and the sea was in front of them and Pharaoh's army was behind them, his people panicked. Musa said: 'No. My Lord is with me.' Allah split the sea. Your impossible situation is not impossible for Allah.", key_lesson:"When there's no way out in front of you and no way back behind you, Allah can split the sea.", ayah_ref:"9:40" },
  { id:"ibrahim_alone", prophet:"Ibrahim عليه السلام", title:"His Own Father Tried to Destroy Him", themes:["family doesn't understand","parents don't get it","standing alone","peer pressure","doing right when everyone else isn't","lonely for the truth","going against the crowd","revert family doesn't accept islam"], story:"Ibrahim عليه السلام grew up in a family and society that worshipped idols. His own father was one of the main idol makers. When Ibrahim spoke the truth — that these idols were nothing — his community turned on him. His father disowned him. They literally built a fire and threw him in it. His own people. And what did Allah do? He made the fire cool and peaceful for Ibrahim. When you're standing for something true and everyone around you — even family — is against you, you're in the company of the Prophets. That fire couldn't touch him because Allah was with him.", key_lesson:"Standing alone for the truth puts you in the best company.", ayah_ref:"3:173" },
  { id:"ayub_loss", prophet:"Ayub عليه السلام", title:"He Lost Everything and Still Didn't Let Go", themes:["loss","losing everything","nothing going right","sick","depressed","nothing left","stripped of blessings","long suffering","grief"], story:"Ayub عليه السلام was one of the most blessed people alive — wealth, family, health. Then he lost it all. His wealth disappeared. His children died. He became severely ill for years. Almost everyone left. And through all of it, his dua was just: 'Adversity has touched me, and You are the Most Merciful of the merciful.' He didn't demand an explanation from Allah. He didn't quit. He just held on. When his trial ended, Allah restored everything — and more. You don't need to know when it ends. You just need to not let go.", key_lesson:"You don't need to know when the trial ends. You just need to not let go of Allah.", ayah_ref:"21:83" },
  { id:"muhammad_grief", prophet:"Muhammad ﷺ", title:"The Year of Grief", themes:["grief","loss","sadness","depression","heartbreak","everything going wrong at once","feeling abandoned","duas not answered","iman low"], story:"The Prophet ﷺ had a year so painful scholars called it The Year of Grief. His wife Khadijah — his closest companion — died. Then his uncle and protector Abu Talib died. He traveled to Taif seeking support and was chased out by mobs who threw stones at him until his feet bled. And it was during a period when revelation had paused and he felt alone that Surah Ad-Duha was revealed. Allah told him: 'Your Lord has not abandoned you.' In his darkest moment, the message from Allah was: I am still here. He never leaves.", key_lesson:"Even the Prophet ﷺ had a year of grief. The message was always: I am still here.", ayah_ref:"93:3" },
  { id:"yunus_darkness", prophet:"Yunus عليه السلام", title:"Three Layers of Darkness and One Dua", themes:["trapped","no way out","made a mistake","my own fault","consequences","rock bottom","darkest point","running from responsibility","sin","relapse","quitting sin"], story:"Yunus عليه السلام left his people without Allah's permission when they frustrated him. He ended up on a sinking ship, was thrown overboard, and was swallowed by a whale. Three layers of darkness — night, ocean, whale's belly. Rock bottom doesn't get more real. And in that darkness he made one of the most powerful duas in the Quran: 'There is no deity except You; exalted are You. Indeed, I have been of the wrongdoers.' He admitted his mistake. He didn't blame anyone else. He turned back to Allah. And Allah brought him out. No matter how deep the darkness, or how much of it was your own fault — that dua works.", key_lesson:"No darkness is too deep for that dua. Admit it, turn back, and Allah will bring you out.", ayah_ref:"21:83" },
  { id:"maryam_judged", prophet:"Maryam عليها السلام", title:"Facing the Impossible Completely Alone", themes:["alone","nobody understands","judged","what will people think","shame","scared of people's opinion","impossible situation","gossip","revert judged"], story:"Maryam عليها السلام was given one of the most difficult situations any person has ever faced — a young unmarried woman about to have a child in a society where that meant complete social destruction. She was so overwhelmed she said 'I wish I had died before this.' Allah sent an angel who said: 'Do not grieve. Your Lord has provided.' She gave birth alone under a palm tree in the desert with no one there. And Allah provided everything she needed. She pointed to her baby, and he spoke in the cradle to defend her. When you're facing judgment alone with no words, Allah can make your circumstances speak for you.", key_lesson:"Allah can make your circumstances defend you when you have no words left.", ayah_ref:"9:40" },
  { id:"muhammad_character", prophet:"Muhammad ﷺ", title:"How He Dealt With People Who Hurt Him", themes:["toxic people","people who hate me","enemies","gossip","backbiting","how to respond","being wronged","anger","want revenge","someone is treating me badly"], story:"There was a woman who would throw garbage on the Prophet ﷺ every time he walked past her house. Every single day. He never reacted. One day he walked past and there was no garbage. He stopped and asked — and found out she was sick. He went to visit her. She was so moved that he came to check on the person who had been tormenting him that she accepted Islam. The Prophet ﷺ said 'I was only sent to perfect good character.' The way you respond to people who hurt you is one of the most powerful forms of dawah.", key_lesson:"Your character in how you respond to people who wrong you is itself an act of worship.", ayah_ref:"16:128" },
  { id:"ibrahim_purpose", prophet:"Ibrahim عليه السلام", title:"Leaving Everything Behind for a Purpose", themes:["purpose","future","uncertainty","leaving comfort zone","scared about future","what is my path","ambition","direction","career","rizq"], story:"Ibrahim عليه السلام was asked by Allah to take his wife Hajar and infant son Ismail to a barren valley with no water and no people — what is now Mecca — and leave them there. No explanation. Just trust. Hajar asked: 'Did Allah command you to do this?' He said yes. She said: 'Then He will not abandon us.' She ran between the hills of Safa and Marwa desperately searching for water. Her running became one of the pillars of Hajj — performed by millions every year. What felt like abandonment in the desert became the foundation of an entire ummah. When Allah calls you into uncertainty, the destination is bigger than you can currently see.", key_lesson:"What looks like abandonment might be the foundation of something millions will benefit from.", ayah_ref:"65:3" },
  { id:"muhammad_salah", prophet:"Muhammad ﷺ", title:"Where He Went When Things Were Hard", themes:["salah","missing prayer","prayer consistency","ibadah","spiritual low","disconnected","lazy with deen","not praying","motivation for worship"], story:"The Prophet ﷺ said that salah was the coolness of his eyes — his comfort, his rest, his relief. When something was difficult, he would go to Bilal and say 'Give us rest through it' — call the adhan so we can pray. Salah was where he went to recharge, not a burden he dragged himself to. He said the first thing we will be asked about on the Day of Judgment is our salah. Not because Allah wants to punish us — but because salah is the direct line between you and Allah. When you feel far from Allah, salah is not what you have to do. It is the way back.", key_lesson:"Salah is not the burden when you're struggling. It's what gets you out of the struggle.", ayah_ref:"2:45" },
];

