// ─────────────────────────────────────────────
// STORAGE HELPERS — with full fallbacks
// ─────────────────────────────────────────────
const memoryStore = [];

async function saveSuggestion(data) {
  try {
    const entry = { ...data, timestamp: new Date().toISOString() };
    memoryStore.push(entry);
    if (typeof window !== "undefined" && window.storage) {
      const existing = await window.storage.get("deen-drop-suggestions").catch(() => null);
      const list = existing ? JSON.parse(existing.value) : [];
      list.push(entry);
      await window.storage.set("deen-drop-suggestions", JSON.stringify(list), true).catch(() => null);
    }
    return true;
  } catch { return false; }
}

async function loadSuggestions() {
  try {
    if (typeof window !== "undefined" && window.storage) {
      const result = await window.storage.get("deen-drop-suggestions", true).catch(() => null);
      if (result) return JSON.parse(result.value);
    }
    return [...memoryStore];
  } catch { return [...memoryStore]; }
}

async function submitToFormspree(data) {
  try {
    if (!FORMSPREE_URL || FORMSPREE_URL.includes("YOUR_FORM_ID")) return false;
    const res = await fetch(FORMSPREE_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json", "Accept": "application/json" },
      body: JSON.stringify(data),
    }).catch(() => null);
    return res && res.ok;
  } catch { return false; }
}

