const EXAMPLES = ["I keep failing no matter how hard I try","I feel disconnected from Allah","I can't stop watching haram content","I'm scared about my future","I feel like my duas aren't being answered","I'm dealing with a toxic friend","My family doesn't accept my Islam","I'm stressed about exams","I keep falling into the same sin","I feel completely alone"];
const RECITERS = [{ id:"Alafasy_128kbps",name:"Mishary Alafasy" },{ id:"AbdurRahmaanAs-Sudais_192kbps",name:"As-Sudais" },{ id:"Husary_128kbps",name:"Al-Husary" }];

function getAudioUrl(s,a,r){ return `https://everyayah.com/data/${r}/${String(s).padStart(3,"0")}${String(a).padStart(3,"0")}.mp3`; }

async function generateResponse(problem) {
  const ayahIndex = QURAN_DB.map(a=>`ID:${a.id} | Themes: ${a.themes.join(", ")}`).join("\n");
  const storyIndex = PROPHET_STORIES.map(s=>`ID:${s.id} | ${s.prophet} - ${s.title} | Themes: ${s.themes.join(", ")}`).join("\n");
  const videoIndex = VIDEO_DB.map(v=>`ID:${v.id} | Topic: ${v.topic} | Themes: ${v.themes.join(", ")}`).join("\n");
  const duaIndex = DUA_DB.map(d=>`ID:${d.id} | Situation: ${d.situation} | Themes: ${d.themes.join(", ")}`).join("\n");

  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method:"POST",
    headers:{ "Content-Type":"application/json" },
    body: JSON.stringify({
      model:"claude-sonnet-4-20250514",
      max_tokens:1024,
      system:`You are the matching engine for Deen Drop, an Islamic app for Muslim teens.

Pick the best ayah ID, story ID, video topic ID, and dua ID from the provided databases. Write a warm peer-level reflection.

CRITICAL RULES:
- ONLY use IDs that exist exactly in the provided databases
- Do NOT generate any Arabic text, translations, or duas yourself
- Return ONLY raw JSON, no markdown, no backticks

JSON format:
{
  "ayah_id": "94:5",
  "story_id": "yusuf_betrayal",
  "video_id": "hardship_general",
  "dua_id": "anxiety_distress",
  "emotion": "one word",
  "why_relevant": "2-3 warm sentences acknowledging their feeling first",
  "reflection": "3-4 sentences making this personal to their exact situation",
  "action": "one small practical thing to do today"
}`,
      messages:[{ role:"user", content:`Problem: ${problem}\n\nQURAN DATABASE:\n${ayahIndex}\n\nPROPHET STORIES DATABASE:\n${storyIndex}\n\nVIDEO DATABASE:\n${videoIndex}\n\nDUA DATABASE:\n${duaIndex}` }]
    })
  });

  if (!res.ok) { const t = await res.text().catch(()=>""); throw new Error(`API ${res.status}: ${t.slice(0,120)}`); }
  const data = await res.json();
  if (data.type==="error") throw new Error(data.error?.message||"Claude API error");
  const raw = (data.content||[]).map(b=>b.text||"").join("").trim();
  if (!raw) throw new Error("Empty response");
  const match = raw.match(/\{[\s\S]*\}/);
  if (!match) throw new Error(`No JSON found: ${raw.slice(0,100)}`);
  const parsed = JSON.parse(match[0]);
  const ayah = QURAN_DB.find(a=>a.id===parsed.ayah_id);
  const story = PROPHET_STORIES.find(s=>s.id===parsed.story_id);
  const videoTopic = VIDEO_DB.find(v=>v.id===parsed.video_id);
  const dua = DUA_DB.find(d=>d.id===parsed.dua_id);
  if (!ayah) throw new Error(`Ayah ID not found: ${parsed.ayah_id}`);
  if (!story) throw new Error(`Story ID not found: ${parsed.story_id}`);
  if (!dua) throw new Error(`Dua ID not found: ${parsed.dua_id}`);
  return { ...parsed, ayah, story, videoTopic, dua };
}

